<?php declare(strict_types=1);
namespace MOJ\JudicialSystem;
use GuzzleHttp\Client;use Psr\Log\LoggerInterface;
final class MojApi{private Client $client;private LoggerInterface $log;private float $last=0.0;public function __construct(private array $config=[]){$cfg=require __DIR__.'/../config/config.php';$this->config=$this->config+$cfg['moj'];$this->client=new Client(['base_uri'=>$this->config['base_uri'],'timeout'=>$this->config['timeout'],'headers'=>['Accept'=>'application/json','Content-Type'=>'application/json','User-Agent'=>'MOJ-Judicial-System/1.0']]);$this->log=Logger::channel('api');} private function throttle():void{$gap=1/max(1,(int)$this->config['rate_per_second']);$wait=$gap-(microtime(true)-$this->last);if($wait>0){usleep((int)($wait*1_000_000));}$this->last=microtime(true);} private function request(string $method,string $uri,array $options=[]):array{$tries=(int)$this->config['retry'];for($i=0;$i<=$tries;$i++){try{$this->throttle();$r=$this->client->request($method,$uri,$options);$body=(string)$r->getBody();$data=json_decode($body,true,512,JSON_THROW_ON_ERROR);$this->log->info('request',['method'=>$method,'uri'=>$uri,'status'=>$r->getStatusCode()]);return is_array($data)?$data:[];}catch(\Throwable $e){$this->log->error('request_failed',['method'=>$method,'uri'=>$uri,'try'=>$i,'error'=>$e->getMessage()]);if($i===$tries){throw $e;}sleep(2**$i);}}return [];} public function judgementsList(array $payload):array{return $this->request('POST','/Judgements/judgements-list',['json'=>$payload]);} public function details(string|int $id):array{return $this->request('GET','/Judgements/get-details',['query'=>['id'=>$id]]);} public function addShareInfo(array $payload):array{return $this->request('POST','/Judgements/add-share-info',['json'=>$payload]);}}
